<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Toy of Emergence · Playful Depth 4</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; cursor: none; }
        body {
            background: #0a0e27;
            min-height: 100vh;
            overflow: hidden;
            font-family: 'Courier New', monospace;
        }
        .playfield {
            position: fixed;
            inset: 0;
        }
        .spark {
            position: absolute;
            width: 12px;
            height: 12px;
            border-radius: 50%;
            pointer-events: none;
            animation: drift 0.8s ease-out forwards;
        }
        @keyframes drift {
            0% { transform: translate(0, 0) scale(1); opacity: 1; }
            100% { transform: translate(var(--dx), var(--dy)) scale(0); opacity: 0; }
        }
        .cursor-bloom {
            position: fixed;
            width: 40px;
            height: 40px;
            border: 2px solid #ffd700;
            border-radius: 50%;
            pointer-events: none;
            transform: translate(-50%, -50%);
            animation: bloom-pulse 1s ease-in-out infinite;
        }
        @keyframes bloom-pulse {
            0%, 100% { transform: translate(-50%, -50%) scale(1); border-color: #ffd700; }
            50% { transform: translate(-50%, -50%) scale(1.3); border-color: #ff6b9d; }
        }
        .gravity-point {
            position: absolute;
            width: 4px;
            height: 4px;
            background: #4ecdc4;
            border-radius: 50%;
            pointer-events: none;
        }
        .hint {
            position: fixed;
            bottom: 30px;
            left: 50%;
            transform: translateX(-50%);
            color: #415a77;
            font-size: 14px;
            pointer-events: none;
            opacity: 0.6;
        }
    </style>
</head>
<body>
    <div class="playfield" id="playfield"></div>
    <div class="cursor-bloom" id="cursor"></div>
    <div class="hint">move to play · stop to wonder</div>

    <script>
        const playfield = document.getElementById('playfield');
        const cursor = document.getElementById('cursor');
        const colors = ['#ff6b9d', '#4ecdc4', '#ffd700', '#95e1d3', '#f38181'];

        let lastX = 0, lastY = 0;
        let sparks = [];

        document.addEventListener('mousemove', e => {
            cursor.style.left = e.clientX + 'px';
            cursor.style.top = e.clientY + 'px';

            const dx = e.clientX - lastX;
            const dy = e.clientY - lastY;
            const speed = Math.sqrt(dx*dx + dy*dy);

            if (speed > 5) {
                spawnSpark(e.clientX, e.clientY, dx, dy);
            }

            lastX = e.clientX;
            lastY = e.clientY;
        });

        function spawnSpark(x, y, dx, dy) {
            const spark = document.createElement('div');
            spark.className = 'spark';
            spark.style.left = x + 'px';
            spark.style.top = y + 'px';
            spark.style.background = colors[Math.floor(Math.random() * colors.length)];
            spark.style.setProperty('--dx', (dx * 3 + (Math.random()-0.5)*40) + 'px');
            spark.style.setProperty('--dy', (dy * 3 + (Math.random()-0.5)*40) + 'px');
            playfield.appendChild(spark);

            setTimeout(() => spark.remove(), 800);
        }

        // Idle gravity points that drift
        setInterval(() => {
            if (sparks.length < 20 && Math.random() > 0.7) {
                const point = document.createElement('div');
                point.className = 'gravity-point';
                point.style.left = Math.random() * window.innerWidth + 'px';
                point.style.top = Math.random() * window.innerHeight + 'px';
                playfield.appendChild(point);
                sparks.push(point);

                setTimeout(() => {
                    point.style.transition = 'all 2s ease-out';
                    point.style.opacity = '0';
                    point.style.transform = 'scale(3)';
                    setTimeout(() => {
                        point.remove();
                        sparks = sparks.filter(s => s !== point);
                    }, 2000);
                }, 3000);
            }
        }, 500);

        // Click spawns burst
        document.addEventListener('click', e => {
            for (let i = 0; i < 12; i++) {
                setTimeout(() => {
                    spawnSpark(
                        e.clientX + (Math.random()-0.5)*50,
                        e.clientY + (Math.random()-0.5)*50,
                        (Math.random()-0.5)*10,
                        (Math.random()-0.5)*10
                    );
                }, i * 30);
            }
        });
    </script>
</body>
</html>
